    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetch trades (response similar for REST & WS)
        //
        //   {
        //       "tradeId": "3263934920",
        //       "instId": "LTC-USDT",
        //       "price": "67.87",
        //       "size": "1",
        //       "side": "buy",
        //       "ts": "1707232020854"
        //   }
        //
        // my trades
        //   {
        //       "instId": "LTC-USDT",
        //       "tradeId": "1440847",
        //       "orderId": "2075705202",
        //       "fillPrice": "67.850000000000000000",
        //       "fillSize": "1.000000000000000000",
        //       "fillPnl": "0.000000000000000000",
        //       "side": "buy",
        //       "positionSide": "net",
        //       "fee": "0.040710000000000000",
        //       "ts": "1707224678878",
        //       "brokerId": ""
        //   }
        //
        // fetchMyTrades spot
        //     {
        //         "instId": "DOGE-USDT",
        //         "tradeId": "6000001623870",
        //         "orderId": "6000011777113",
        //         "fillPrice": "0.091480000000000000",
        //         "fillSize": "30.000000000000000000",
        //         "fillPnl": null,
        //         "side": "buy",
        //         "fee": "0.030000000000000000",
        //         "ts": "1775213753407",
        //         "brokerId": null,
        //         "feeCurrency": "base_currency"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(trade, "tradeId");
        Object marketId = this.safeString(trade, "instId");
        market = this.safeMarket(marketId, market, "-");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(trade, "ts");
        Object price = this.safeString2(trade, "price", "fillPrice");
        Object amount = this.safeString2(trade, "size", "fillSize");
        Object side = this.safeString(trade, "side");
        Object orderId = this.safeString(trade, "orderId");
        Object feeCost = this.safeString(trade, "fee");
        Object fee = null;
        Object feeCurrency = this.safeString(trade, "feeCurrency");
        Object isSpot = !Helpers.isEqual(feeCurrency, null);
        if (Helpers.isTrue(Helpers.isEqual(feeCurrency, null)))
        {
            feeCurrency = Helpers.GetValue(market, "settle");
        } else if (Helpers.isTrue(Helpers.isEqual(feeCurrency, "base_currency")))
        {
            feeCurrency = Helpers.GetValue(market, "base");
        } else if (Helpers.isTrue(Helpers.isEqual(feeCurrency, "quote_currency")))
        {
            feeCurrency = Helpers.GetValue(market, "quote");
        }
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            final Object finalFeeCurrency = feeCurrency;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", finalFeeCurrency );
            }};
        }
        if (Helpers.isTrue(isSpot))
        {
            Object spotSymbol = Helpers.add(Helpers.add(Helpers.GetValue(market, "base"), "/"), Helpers.GetValue(market, "quote"));
            Object cost = this.parseNumber(Precise.stringMul(price, amount));
            final Object finalFeeCost_2 = feeCost;
            final Object finalFeeCurrency_2 = feeCurrency;
            Object result = new java.util.HashMap<String, Object>() {{
                put( "info", trade );
                put( "timestamp", timestamp );
                put( "datetime", BlofinCore.this.iso8601(timestamp) );
                put( "symbol", spotSymbol );
                put( "id", id );
                put( "order", orderId );
                put( "type", null );
                put( "takerOrMaker", null );
                put( "side", side );
                put( "price", BlofinCore.this.parseNumber(price) );
                put( "amount", BlofinCore.this.parseNumber(amount) );
                put( "cost", cost );
                put( "fee", new java.util.HashMap<String, Object>() {{
                    put( "cost", BlofinCore.this.parseNumber(finalFeeCost_2) );
                    put( "currency", finalFeeCurrency_2 );
                }} );
            }};
            return result;
        } else
        {
            final Object finalFee = fee;
            return this.safeTrade(new java.util.HashMap<String, Object>() {{
                put( "info", trade );
                put( "timestamp", timestamp );
                put( "datetime", BlofinCore.this.iso8601(timestamp) );
                put( "symbol", symbol );
                put( "id", id );
                put( "order", orderId );
                put( "type", null );
                put( "takerOrMaker", null );
                put( "side", side );
                put( "price", price );
                put( "amount", amount );
                put( "cost", null );
                put( "fee", finalFee );
            }}, market);
        }
    }

