    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // response similar for REST & WS
        //
        //     {
        //         instType: 'SWAP',
        //         instId: 'LTC-USDT',
        //         marginMode: 'cross',
        //         positionId: '644159',
        //         positionSide: 'net',
        //         positions: '1',
        //         availablePositions: '1',
        //         averagePrice: '68.16',
        //         unrealizedPnl: '0.80631223',
        //         unrealizedPnlRatio: '0.03548909463028169',
        //         leverage: '3',
        //         liquidationPrice: '10.116655172370356435',
        //         markPrice: '68.96',
        //         initialMargin: '22.988770743333333333',
        //         margin: '', // this field might not exist in rest response
        //         marginRatio: '152.523509620342499273',
        //         maintenanceMargin: '0.34483156115',
        //         adl: '4',
        //         createTime: '1707235776528',
        //         updateTime: '1707235776528'
        //     }
        //
        //
        //    positions-history
        //
        //            {
        //                "positionId": "1000000722711",
        //                "instId": "BTC-USDT",
        //                "instType": "SWAP",
        //                "marginMode": "cross",
        //                "positionSide": "net",
        //                "createTime": "1777995583329",
        //                "updateTime": "1777995588333",
        //                "leverage": "50",
        //                "realizedPnl": "-0.058776036",
        //                "realizedPnlRatio": "-0.060061275216094155",
        //                "fee": "-0.058716036"
        //                "historyId": "110307402",
        //                "closePositions": "0.0006",
        //                "maxPositions": "0.0006",
        //                "liquidationPositions": "0",
        //                "openAveragePrice": "81550.1",
        //                "closeAveragePrice": "81550",
        //            },
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "instId");
        market = this.safeMarket(marketId, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object pos = this.safeString(position, "positions");
        Object contractsAbs = Precise.stringAbs(pos);
        Object side = this.safeString(position, "positionSide");
        Object hedged = !Helpers.isEqual(side, "net");
        Object contracts = this.parseNumber(contractsAbs);
        if (Helpers.isTrue(!Helpers.isEqual(pos, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(side, "net")))
            {
                if (Helpers.isTrue(Precise.stringGt(pos, "0")))
                {
                    side = "long";
                } else if (Helpers.isTrue(Precise.stringLt(pos, "0")))
                {
                    side = "short";
                } else
                {
                    side = null;
                }
            }
        }
        Object contractSize = this.safeNumber(market, "contractSize");
        Object contractSizeString = this.numberToString(contractSize);
        Object markPriceString = this.safeString(position, "markPrice");
        Object notionalString = this.safeString(position, "notionalUsd");
        if (Helpers.isTrue(Helpers.GetValue(market, "inverse")))
        {
            notionalString = Precise.stringDiv(Precise.stringMul(contractsAbs, contractSizeString), markPriceString);
        }
        Object notional = this.parseNumber(notionalString);
        Object marginMode = this.safeString(position, "marginMode");
        Object initialMarginString = null;
        Object entryPriceString = this.safeString2(position, "averagePrice", "openAveragePrice");
        Object unrealizedPnlString = this.safeString(position, "unrealizedPnl");
        Object leverageString = this.safeString(position, "leverage");
        Object initialMarginPercentage = null;
        Object collateralString = null;
        if (Helpers.isTrue(Helpers.isEqual(marginMode, "cross")))
        {
            initialMarginString = this.safeString(position, "initialMargin");
            collateralString = Precise.stringAdd(initialMarginString, unrealizedPnlString);
        } else if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
        {
            initialMarginPercentage = Precise.stringDiv("1", leverageString);
            collateralString = this.safeString(position, "margin");
        }
        Object maintenanceMarginString = this.safeString(position, "maintenanceMargin");
        Object maintenanceMargin = this.parseNumber(maintenanceMarginString);
        Object maintenanceMarginPercentageString = Precise.stringDiv(maintenanceMarginString, notionalString);
        if (Helpers.isTrue(Helpers.isEqual(initialMarginPercentage, null)))
        {
            initialMarginPercentage = this.parseNumber(Precise.stringDiv(initialMarginString, notionalString, 4));
        } else if (Helpers.isTrue(Helpers.isEqual(initialMarginString, null)))
        {
            initialMarginString = Precise.stringMul(initialMarginPercentage, notionalString);
        }
        Object rounder = "0.00005"; // round to closest 0.01%
        Object maintenanceMarginPercentage = this.parseNumber(Precise.stringDiv(Precise.stringAdd(maintenanceMarginPercentageString, rounder), "1", 4));
        Object liquidationPrice = this.safeNumber(position, "liquidationPrice");
        Object percentageString = this.safeString(position, "unrealizedPnlRatio");
        Object percentage = this.parseNumber(Precise.stringMul(percentageString, "100"));
        Object timestamp = this.safeInteger(position, "updateTime");
        Object marginRatio = this.parseNumber(Precise.stringDiv(maintenanceMarginString, collateralString, 4));
        final Object finalMarginMode = marginMode;
        final Object finalSide = side;
        final Object finalCollateralString = collateralString;
        final Object finalInitialMarginString = initialMarginString;
        final Object finalInitialMarginPercentage = initialMarginPercentage;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", symbol );
            put( "notional", notional );
            put( "marginMode", finalMarginMode );
            put( "liquidationPrice", liquidationPrice );
            put( "entryPrice", BlofinCore.this.parseNumber(entryPriceString) );
            put( "exitPrice", BlofinCore.this.safeNumber(position, "closeAveragePrice") );
            put( "unrealizedPnl", BlofinCore.this.parseNumber(unrealizedPnlString) );
            put( "realizedPnl", BlofinCore.this.safeNumber(position, "realizedPnl") );
            put( "percentage", percentage );
            put( "contracts", contracts );
            put( "contractSize", contractSize );
            put( "markPrice", BlofinCore.this.parseNumber(markPriceString) );
            put( "lastPrice", null );
            put( "side", finalSide );
            put( "hedged", hedged );
            put( "timestamp", timestamp );
            put( "datetime", BlofinCore.this.iso8601(timestamp) );
            put( "lastUpdateTimestamp", null );
            put( "maintenanceMargin", maintenanceMargin );
            put( "maintenanceMarginPercentage", maintenanceMarginPercentage );
            put( "collateral", BlofinCore.this.parseNumber(finalCollateralString) );
            put( "initialMargin", BlofinCore.this.parseNumber(finalInitialMarginString) );
            put( "initialMarginPercentage", BlofinCore.this.parseNumber(finalInitialMarginPercentage) );
            put( "leverage", BlofinCore.this.parseNumber(leverageString) );
            put( "marginRatio", marginRatio );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

    /**
     * @method
     * @name blofin#fetchLeverages
     * @description fetch the set leverage for all contract markets
     * @see https://docs.blofin.com/index.html#get-multiple-leverage
     * @param {string[]} symbols a list of unified market symbols, required on blofin
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.marginMode] 'cross' or 'isolated'
     * @returns {object} a list of [leverage structures]{@link https://docs.ccxt.com/?id=leverage-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchLeverages(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            if (Helpers.isTrue(Helpers.isEqual(symbols, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchLeverages() requires a symbols argument")) ;
            }
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("fetchLeverages", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(marginMode, null)))
            {
                marginMode = this.safeString(parameters, "marginMode", "cross"); // cross as default marginMode
            }
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(marginMode, "cross"))) && Helpers.isTrue((!Helpers.isEqual(marginMode, "isolated")))))
            {
                throw new BadRequest((String)Helpers.add(this.id, " fetchLeverages() requires a marginMode parameter that must be either cross or isolated")) ;
            }
            symbols = this.marketSymbols(symbols);
            Object symbolsList = symbols;
            Object instIds = "";
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbolsList)); i++)
            {
                Object entry = Helpers.GetValue(symbolsList, i);
                Object entryMarket = this.market(entry);
                if (Helpers.isTrue(Helpers.isGreaterThan(i, 0)))
                {
                    instIds = Helpers.add(Helpers.add(instIds, ","), Helpers.GetValue(entryMarket, "id"));
                } else
                {
                    instIds = Helpers.add(instIds, Helpers.GetValue(entryMarket, "id"));
                }
            }
            final Object finalInstIds = instIds;
            final Object finalMarginMode = marginMode;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "instId", finalInstIds );
                put( "marginMode", finalMarginMode );
            }};
            Object response = (this.privateGetAccountBatchLeverageInfo(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": "0",
            //         "msg": "success",
            //         "data": [
            //             {
            //                 "leverage": "3",
            //                 "marginMode": "cross",
            //                 "instId": "BTC-USDT"
            //             },
            //         ]
            //     }
            //
            Object leverages = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseLeverages(leverages, symbols, "instId");
        });

    }

